IF OBJECT_ID(N'POC.MA_PARTNER',N'U') IS NULL CREATE TABLE POC.MA_PARTNER (CD_FIRM varchar(10) NOT NULL,CD_PARTNER varchar(20) NOT NULL,NM_PARTNER nvarchar(100) NOT NULL,NO_COMPANY varchar(20) NOT NULL,YN_USE char(1) NOT NULL CONSTRAINT CK_MA_PARTNER_USE CHECK(YN_USE IN('Y','N')),CONSTRAINT PK_MA_PARTNER PRIMARY KEY(CD_FIRM,CD_PARTNER));
IF OBJECT_ID(N'POC.MA_ITEM',N'U') IS NULL CREATE TABLE POC.MA_ITEM (CD_FIRM varchar(10) NOT NULL,CD_ITEM varchar(30) NOT NULL,NM_ITEM nvarchar(100) NOT NULL,STND_ITEM nvarchar(100) NOT NULL,UNIT_ITEM varchar(10) NOT NULL,YN_USE char(1) NOT NULL CONSTRAINT CK_MA_ITEM_USE CHECK(YN_USE IN('Y','N')),CONSTRAINT PK_MA_ITEM PRIMARY KEY(CD_FIRM,CD_ITEM));
IF OBJECT_ID(N'POC.MA_WH',N'U') IS NULL CREATE TABLE POC.MA_WH (CD_FIRM varchar(10) NOT NULL,CD_WH varchar(20) NOT NULL,NM_WH nvarchar(100) NOT NULL,YN_USE char(1) NOT NULL CONSTRAINT CK_MA_WH_USE CHECK(YN_USE IN('Y','N')),CONSTRAINT PK_MA_WH PRIMARY KEY(CD_FIRM,CD_WH));
